import{_ as a,o,c as t,a3 as n}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"Workspace Management","description":"Learn how to manage workspaces, notes, folders, and navigate the dashboard in Notely.","frontmatter":{"title":"Workspace Management","description":"Learn how to manage workspaces, notes, folders, and navigate the dashboard in Notely.","keywords":"workspace, landing screen, folders, sidebar, dashboard, favorites, continue writing","category":"Workspace"},"headers":[],"relativePath":"workspace/index.md","filePath":"workspace/index.md","lastUpdated":1784303924000}'),r={name:"workspace/index.md"};function s(i,e,l,d,c,h){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="workspace-overview" tabindex="-1">Workspace Overview <a class="header-anchor" href="#workspace-overview" aria-label="Permalink to &quot;Workspace Overview&quot;">​</a></h1><p>A workspace is the single source of truth for your notes in Notely. It maps to a folder on your local filesystem containing Markdown documents and asset subfolders.</p><h2 id="_1-landing-dashboard" tabindex="-1">1. Landing Dashboard <a class="header-anchor" href="#_1-landing-dashboard" aria-label="Permalink to &quot;1. Landing Dashboard&quot;">​</a></h2><p>When you open a workspace, you are greeted by the landing dashboard, which provides quick access to recent work and workspace health:</p><ul><li><strong>Continue Writing</strong>: Shows the single most recently edited note to resume editing instantly.</li><li><strong>Recent Notes</strong>: Displays a chronological list of recent notes.</li><li><strong>Favorites</strong>: Starred notes for immediate access.</li><li><strong>Open Tasks</strong>: Summarizes unchecked tasks across the workspace.</li></ul><hr><h2 id="_2-note-and-folder-creation" tabindex="-1">2. Note and Folder Creation <a class="header-anchor" href="#_2-note-and-folder-creation" aria-label="Permalink to &quot;2. Note and Folder Creation&quot;">​</a></h2><ul><li><strong>New Note</strong>: Create notes from <strong>File → New Note</strong> (<code>Ctrl + N</code>).</li><li><strong>New Folder</strong>: Create subfolders inside the sidebar list view to group notes logically.</li><li><strong>Rename &amp; Delete</strong>: Available from the note context menu. Deleted files are safely moved to the &quot;Removed&quot; folder pool managed by Notely.</li></ul><hr><h2 id="_3-density-layout-views" tabindex="-1">3. Density &amp; Layout Views <a class="header-anchor" href="#_3-density-layout-views" aria-label="Permalink to &quot;3. Density &amp; Layout Views&quot;">​</a></h2><p>Customize how you browse your workspace contents:</p><ul><li><strong>Tile View</strong>: Card-style layout showing note content previews.</li><li><strong>Table View</strong>: Compact, grid-based list view for scanning large note lists quickly. Double-click any note row in Table View to open it immediately.</li><li><strong>Comfortable Density</strong>: Added margins and breathing room.</li><li><strong>Compact Density</strong>: High-density display for reviewing many documents at once.</li></ul><p>Switch views from the <strong>View</strong> menu or the Command Palette.</p><hr><h2 id="_4-unsaved-changes-guard" tabindex="-1">4. Unsaved Changes Guard <a class="header-anchor" href="#_4-unsaved-changes-guard" aria-label="Permalink to &quot;4. Unsaved Changes Guard&quot;">​</a></h2><p>If you attempt to close a note tab with unsaved edits, Notely will display a <strong>Discard Changes</strong> confirmation dialog to prevent accidental data loss. You can choose to save changes first, discard them, or cancel the action to return to editing.</p>',16)])])}const p=a(r,[["render",s]]);export{u as __pageData,p as default};
